import{_ as c,r as s,o as d,c as h,a,b as e,d as t,e as n}from"./app-ae419367.js";const l={},r=a("h1",{id:"dify简介",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#dify简介","aria-hidden":"true"},"#"),e(" Dify简介")],-1),o=a("strong",null,"Dify",-1),M={href:"https://docs.dify.ai/v/zh-hans/learn-more/extended-reading/what-is-llmops",target:"_blank",rel:"noopener noreferrer"},p=n('<p><img src="https://qal900jc4hv.feishu.cn/space/api/box/stream/download/asynccode/?code=NGZmZThjODRlNTZhZjI2M2I5Mzk0MTg5ODg1YzhlYmFfQVFzelBGTmtiR2cyN0VwajdiV21zNXczZ2NJZ3o1NUNfVG9rZW46SG5LdGJhc0RQb0JtWEN4VGRzSmNEaVlYbmFkXzE3MjM3OTQ3MjE6MTcyMzc5ODMyMV9WNA" alt="img"></p><p>Dify 内置了构建 LLM 应用所需的关键技术栈，包括对数百个模型的支持、直观的 Prompt 编排界面、高质量的 RAG 引擎、稳健的 Agent 框架、灵活的流程编排，并同时提供了一套易用的界面和 API。这为开发者节省了许多重复造轮子的时间，使其可以专注在创新和业务需求上。</p><p><img src="https://qal900jc4hv.feishu.cn/space/api/box/stream/download/asynccode/?code=OTAzYzMzZGYzM2I4ZjUzN2ZjN2IyYzQ1YjViZTc0NzRfbUtqSUtiY3A5MG5ISUhxTDdWMEY3SERYS1NianRnTThfVG9rZW46UkRPZmJjbnhLb251TjV4UXB6MmM0ZUFZbkhmXzE3MjM3OTQ3MjE6MTcyMzc5ODMyMV9WNA" alt="img"></p><p>Dify 是<strong>开源</strong>的，它由一个专业的全职团队和社区共同打造。可以基于任何模型自部署类似 Assistants API 和 GPTs 的能力，在灵活和安全的基础上，同时保持对数据的完全控制。</p><p><img src="https://qal900jc4hv.feishu.cn/space/api/box/stream/download/asynccode/?code=YWMwYTJlNGFhMGU5ODFmMTIzZTljNDA3ODkzODQ3MDZfMHEyQ2xJck5JMGRKUmVtaDFqUlRLQ0dETHVsOHk0NTZfVG9rZW46TkhOcWJ2NTN2b1lyNGx4dkVxVGNlV1l4bmpOXzE3MjM3OTQ3MjE6MTcyMzc5ODMyMV9WNA" alt="img"></p><h1 id="_1-dify-vs-其他ai开发平台" tabindex="-1"><a class="header-anchor" href="#_1-dify-vs-其他ai开发平台" aria-hidden="true">#</a> 1 Dify vs 其他AI开发平台</h1><p>Didy的主要特点：</p><ul><li>主要开发成员来自中国，中文文档较完备</li><li>支持API拓展，可以通过API拓展方式实现使用外部工具获取额外数据组装至Prompt中作为额外信息</li><li>支持大模型类型较多，目前已经支持的模型供应商包括OpenAI、Azure OpenAI Service、Hugging Face、讯飞星火、文心一言、通义千问、Minimax等，在官方文档上也有完备的开源模型接入手册</li><li>首创的可视化知识库管理界面，支持分段预览和召回效果测试</li><li>截止2024Q1内置超过30款Agent，通过文档搭建、发布Agent比较方便</li><li>可以通过可视化界面快速拖拉拽搭建工作流，不同的节点可以实现知识检索、问题分类、条件分支、代码执行、参数提取等工作</li><li>支持本地部署，搭建私有化知识库及AI助理；提供企业级LLMOps平台可以与其他系统集成，通过可视化的工具和流程运维、监控、标注和持续优化</li></ul><p><img src="https://qal900jc4hv.feishu.cn/space/api/box/stream/download/asynccode/?code=YTA2MjliMzE0MzVkYTNiM2Y2OGFjYzMwNjlkOTU2ZjRfc0NQRlU5M0p2NTlhOVA4cElsaGxpR2JKUWJXd1VjVlhfVG9rZW46UmR4UmIwZkdmb0ZZMHN4akhIZWN2UUk1bnBmXzE3MjM3OTQ3MjE6MTcyMzc5ODMyMV9WNA" alt="img"></p><h1 id="_2-主要功能" tabindex="-1"><a class="header-anchor" href="#_2-主要功能" aria-hidden="true">#</a> 2 主要功能</h1><h2 id="_2-1-创建应用" tabindex="-1"><a class="header-anchor" href="#_2-1-创建应用" aria-hidden="true">#</a> 2.1 创建应用</h2><p>可以通过3种方式在Dify创建应用：</p><ul><li>基于应用模板创建</li><li>创建空白应用</li><li>通过DSL文件导入</li></ul><h4 id="基于应用模板创建" tabindex="-1"><a class="header-anchor" href="#基于应用模板创建" aria-hidden="true">#</a> 基于应用模板创建</h4><p>Dify官方提供了多种模板，包括知识库、聊天机器人、翻译等。</p><p><img src="https://qal900jc4hv.feishu.cn/space/api/box/stream/download/asynccode/?code=MzZkNDkwZjYyZjRiZjAxYmI0MGM2YTZmN2ZmYjE0MGFfRjJDcjl3SW5jRWpvcE11ejZPTVdhMFZvRTlTbU9sYjNfVG9rZW46SzV1SGJ2UjJjb3FVbUd4dGlITmNBSzFzbmJiXzE3MjM3OTQ3MjE6MTcyMzc5ODMyMV9WNA" alt="img"></p><h4 id="创建空白应用" tabindex="-1"><a class="header-anchor" href="#创建空白应用" aria-hidden="true">#</a> 创建空白应用</h4><p>如果需要在 Dify 上创建一个空白应用，你可以从导航选择 「工作室」 ，在应用列表内选择 「从空白创建 」。</p><p><img src="https://qal900jc4hv.feishu.cn/space/api/box/stream/download/asynccode/?code=Mjk4OWMxNDY2YjRkYTQ0OGVjYTNlMTNjNzMwNDNkMDJfMnVmWENnd2J0cUcyOWNRWlNKeU94bHVYTnZpeHJFSTRfVG9rZW46WWZKWmJmZmF0bzF0Nnl4UWlBQWNUbUFKbmFiXzE3MjM3OTQ3MjE6MTcyMzc5ODMyMV9WNA" alt="img"></p><h4 id="通过dsl文件导入" tabindex="-1"><a class="header-anchor" href="#通过dsl文件导入" aria-hidden="true">#</a> 通过DSL文件导入</h4><p>从工作室选择 「 导入DSL 文件 」，导入后将直接加载原应用的所有配置信息。</p><p><img src="https://qal900jc4hv.feishu.cn/space/api/box/stream/download/asynccode/?code=ZWU3MDI3NmI4ZmQzMDQ4ZjdjOTZhNWU0M2RiZWRkOWJfT3RlYjZDcHZtYjNSSDBYMmlFM0dOdkJOMEhZeFpLUXJfVG9rZW46UjlsUWJ4M0Jsb0U4N2Z4a3ZvN2NiVTJubmxmXzE3MjM3OTQ3MjE6MTcyMzc5ODMyMV9WNA" alt="img"></p><h2 id="_2-2-搭建工作流" tabindex="-1"><a class="header-anchor" href="#_2-2-搭建工作流" aria-hidden="true">#</a> 2.2 搭建工作流</h2><p>工作流通过将复杂的任务分解成较小的步骤（节点）降低系统复杂度，减少了对提示词技术和模型推理能力的依赖，提高了 LLM 应用面向复杂任务的性能，提升了系统的可解释性、稳定性和容错性。</p><p>Dify 工作流分为两种类型：</p><ul><li><strong>Chatflow</strong>：面向对话类情景，包括客户服务、语义搜索、以及其他需要在构建响应时进行多步逻辑的对话式应用程序。</li><li><strong>Workflow</strong>：面向自动化和批处理情景，适合高质量翻译、数据分析、内容生成、电子邮件自动化等应用程序。</li></ul><p><img src="https://qal900jc4hv.feishu.cn/space/api/box/stream/download/asynccode/?code=MGZmZmZlMjE0MGRiNmZjZjY3Y2ZhZTRiMjJlZDRlZTFfTXE0ZDZZTlV4d0F6SzBzd2pxYmpmZlpjRUJxUGhleDBfVG9rZW46RE9LSGJBcFVsb3hJQ1l4S0lQMGNTQVpmbnlzXzE3MjM3OTQ3MjE6MTcyMzc5ODMyMV9WNA" alt="img"></p><h2 id="_2-3-搭建知识库" tabindex="-1"><a class="header-anchor" href="#_2-3-搭建知识库" aria-hidden="true">#</a> 2.3 搭建知识库</h2><p>在 Dify 主导航栏中点击知识库，在该页面你可以看到已有的知识库。可以点击 <strong>创建知识库</strong> 进入创建向导。</p><p><img src="https://qal900jc4hv.feishu.cn/space/api/box/stream/download/asynccode/?code=YTNhMTBiZTM2ZmIxZDZjMWJjMjJjNzQ5ZTViOTA4YzlfVmczb05oNURNOUJDbUpXWjFwWFFEVkp6N0Jud0ZCU1dfVG9rZW46QnZhMGJnY2R5bzEycFd4bnRmYmNmd1ZVbjE2XzE3MjM3OTQ3MjE6MTcyMzc5ODMyMV9WNA" alt="img"></p><h1 id="_3-接入微信" tabindex="-1"><a class="header-anchor" href="#_3-接入微信" aria-hidden="true">#</a> 3 接入微信</h1><h2 id="_3-1-登录dify官方应用平台" tabindex="-1"><a class="header-anchor" href="#_3-1-登录dify官方应用平台" aria-hidden="true">#</a> 3.1 <strong>登录Dify官方应用平台</strong></h2><p><img src="https://qal900jc4hv.feishu.cn/space/api/box/stream/download/asynccode/?code=YTlmNzljNWQxMzFjMGJlZmQxYjUxMjk2N2I0NTk4YzdfUVlDcVY5UDZoYndvSFBtZThaeFhhRzFtRmNhTGhjYzVfVG9rZW46VDVmbWJFajZZbzRUTTR4N3ZaYmNOZnpMbnFyXzE3MjM3OTQ3MjE6MTcyMzc5ODMyMV9WNA" alt="img"></p><h2 id="_3-2-搭建流程" tabindex="-1"><a class="header-anchor" href="#_3-2-搭建流程" aria-hidden="true">#</a> 3.2 搭建流程</h2><p>https://docs.dify.ai/v/zh-hans/learn-more/use-cases/dify-on-wechat</p><p>需要注意：</p><p>1、最好是用微信小号登录，防止大号被封</p><p>2、需要在本地跑代码，提前安装git、python等环境</p><h2 id="_3-3-更多玩法" tabindex="-1"><a class="header-anchor" href="#_3-3-更多玩法" aria-hidden="true">#</a> 3.3 更多玩法</h2><p>训练出专属于“你”的问答机器人：https://docs.dify.ai/v/zh-hans/learn-more/use-cases/train-a-qa-chatbot-that-belongs-to-you</p><p>在几分钟内创建一个带有业务数据的官网 AI 智能客服：https://docs.dify.ai/v/zh-hans/learn-more/use-cases/create-an-ai-chatbot-with-business-data-in-minutes</p><h1 id="参考文档" tabindex="-1"><a class="header-anchor" href="#参考文档" aria-hidden="true">#</a> 参考文档</h1><ol><li>https://docs.dify.ai/v/zh-hans</li><li>https://juejin.cn/post/7372586171916304421?searchId=20240610224237CD143374053B877BB5CF</li><li>https://cloud.dify.ai/apps</li><li>https://blog.csdn.net/qq_43128256/article/details/138283567</li></ol>',43);function m(j,Z){const i=s("ExternalLinkIcon");return d(),h("div",null,[r,a("p",null,[o,e(" 是一款开源的大语言模型(LLM) 应用开发平台。它融合了后端即服务（Backend as Service）和 "),a("a",M,[e("LLMOps"),t(i)]),e(" 的理念，使开发者可以快速搭建生产级的生成式 AI 应用。")]),p])}const N=c(l,[["render",m],["__file","20240612.html.vue"]]);export{N as default};
